// Build Gemini prompt request — white-label professional, dominant #0860D2 + #FFAF3B accent
const blogTitle = $json['Blog Title'] || 'Untitled';
const content   = $json['Summary/Content'] || '';
const slug      = blogTitle.toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 50);

const prompt = `professional IMAGE PROMPTS

Blog Title: ${blogTitle}
Blog Content: ${content.substring(0, 600)}

Create 3 professional professional image prompts using EXACTLY these brand colors:
- PRIMARY: #0860D2 (deep blue — use as DOMINANT color: backgrounds, large shapes, key elements)
- ACCENT:  #FFAF3B (warm amber/gold — highlights, CTAs, focal accents — use moderately)
- SECONDARY: #9ACA3C (green — success/growth elements — use sparingly)
- LIGHT: #6DCFF6 (cyan — tech/digital glows — use sparingly)
- Text on dark: white

Design rules:
- NO logos, NO text, NO brand names, NO watermarks
- Clean professional modern B2B aesthetic
- All images 16:9 horizontal
- Heavy #0860D2 base, #FFAF3B warm highlights on focal points

1. HERO: Ultra-realistic 3D abstract scene. Deep #0860D2 background. Floating geometric 3D shapes, glowing data streams, glassmorphism panels. #FFAF3B amber glow on key focal element. Depth of field, cinematic lighting. Professional and modern.

2. INFO: Flat isometric 3D infographic. #0860D2 background. Clean isometric icons showing a process flow or system diagram relevant to the blog. #FFAF3B highlights on important steps/nodes. Minimalist vector style, crisp.

3. PHOTO: Cinematic business lifestyle photography. Modern office or city environment. Strong #0860D2 color grade. Warm #FFAF3B light source (window or lamp). Business context — no identifiable faces, no logos.

Respond with JSON only (no markdown, no code blocks):
{"hero":{"prompt":"...","seo":{"filename":"...","alt":"...","description":"..."}},"info":{"prompt":"...","seo":{"filename":"...","alt":"...","description":"..."}},"photo":{"prompt":"...","seo":{"filename":"...","alt":"...","description":"..."}}}`;

return {
  json: {
    ...$json,
    slug,
    requestBody: {
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.85, maxOutputTokens: 2048 }
    }
  }
};

// Parse Gemini prompt response — use PAIRED blog row from Build Request
const raw     = $json.candidates[0].content.parts[0].text;
const clean   = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const prompts = JSON.parse(clean.match(/\{[\s\S]*\}/)[0]);

// Paired item from Build Request contains the original blog row
const blog = $('Build Request').item.json;

return {
  json: {
    blogId:      blog.ID || blog.id || String(blog.row_number || '1'),
    rowNumber:   blog.row_number || 2,
    slug:        blog.slug || 'blog',
    blogTitle:   blog['Blog Title'] || '',
    prompts
  }
};

// Attach binary image data with all metadata
const item = $input.item;

if (!item || !item.binary) {
  return {
    json: {
      imageType:   item?.json?.imageType   || 'unknown',
      filename:    item?.json?.filename    || 'failed.png',
      altText:     item?.json?.altText     || '',
      description: item?.json?.description || '',
      blogId:      item?.json?.blogId      || '1',
      rowNumber:   item?.json?.rowNumber   || 2,
      success: false,
      error: 'No image binary data'
    }
  };
}

const binaryKey  = Object.keys(item.binary)[0];
const binaryData = item.binary[binaryKey];

return {
  json: {
    imageType:   item.json.imageType,
    filename:    item.json.filename,
    altText:     item.json.altText,
    description: item.json.description,
    blogId:      item.json.blogId,
    rowNumber:   item.json.rowNumber,
    success: true
  },
  binary: {
    data: Object.assign({}, binaryData, { fileName: item.json.filename })
  }
};

// Build SEO metadata prompt for Gemini
const d        = $json;
const blogRow  = $('Build Request').item.json;
const title    = blogRow['Blog Title'] || '';
const summary  = (blogRow['Summary/Content'] || '').substring(0, 500);

const typeDesc = {
  hero:  'abstract 3D hero banner — main visual for the blog post',
  info:  'isometric infographic / process diagram about the blog topic',
  photo: 'business lifestyle photo related to the blog topic'
}[d.imageType] || d.imageType;

const promptText = 'You are an SEO content specialist for a subscription product.\n'
  + 'Generate SEO-optimized metadata for a blog post image.\n\n'
  + 'Blog Title: ' + title + '\n'
  + 'Blog Summary: ' + summary + '\n'
  + 'Image Type: ' + d.imageType + ' (' + typeDesc + ')\n'
  + 'Current Filename: ' + d.filename + '\n\n'
  + 'Rules:\n'
  + '- filename: lowercase, hyphens only, 40-65 chars, descriptive keywords, ends with .jpg, NO brand names\n'
  + '- alt: 120-150 chars, describes EXACTLY what the image shows, keyword-rich, natural language\n'
  + '- description: 150-160 chars, SEO image meta description with main topic keywords\n\n'
  + 'JSON only, no markdown:\n{"filename":"...","alt":"...","description":"..."}';

return {
  json: {
    imageType:   d.imageType,
    filename:    d.filename,
    altText:     d.altText,
    description: d.description,
    blogId:      d.blogId,
    rowNumber:   d.rowNumber,
    driveId:     d.driveId,
    driveUrl:    d.driveUrl,
    seoRequest: {
      contents: [{ parts: [{ text: promptText }] }],
      generationConfig: { temperature: 0.3, maxOutputTokens: 512 }
    }
  }
};

// Parse SEO Agent response, merge with image metadata
const geminiResp = $json;
const prev       = $('SEO Request').item.json;

let filename    = prev.filename    || 'image.jpg';
let altText     = prev.altText     || '';
let description = prev.description || '';

try {
  const raw   = geminiResp.candidates[0].content.parts[0].text;
  const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const seo   = JSON.parse(clean.match(/\{[\s\S]*\}/)[0]);
  if (seo.filename)    filename    = seo.filename;
  if (seo.alt)         altText     = seo.alt;
  if (seo.description) description = seo.description;
} catch(e) {
  console.log('SEO parse fallback — using original metadata. Error:', e.message);
}

// Ensure .jpg extension
if (!filename.endsWith('.jpg') && !filename.endsWith('.png')) {
  filename = filename.replace(/\.[^.]+$/, '') + '.jpg';
}

console.log('SEO [' + prev.imageType + ']: ' + filename);

return {
  json: {
    imageType:   prev.imageType,
    filename,
    altText,
    description,
    blogId:      prev.blogId,
    rowNumber:   prev.rowNumber,
    driveId:     prev.driveId,
    driveUrl:    prev.driveUrl
  }
};

// Restore full SEO metadata after Drive file rename
const seo = $('Parse SEO').item.json;

console.log('Final [' + seo.imageType + ']: ' + seo.filename + ' | row:' + seo.rowNumber);

return { json: seo };

// Group image results by blog (rowNumber) — one output per blog
const items = $input.all();

console.log('FORMAT DATA — received', items.length, 'items');

const byBlog = {};

items.forEach(item => {
  const d      = item.json || {};
  const rowNum = d.rowNumber || 2;

  if (!byBlog[rowNum]) {
    byBlog[rowNum] = {
      row_number:       rowNum,
      Status:           'partial',
      'Hero Image':     '', 'Hero Alt':        '', 'Hero Description':  '', 'Hero URL':  '',
      'Info Image':     '', 'Info Alt':        '', 'Info Description':  '', 'Info URL':  '',
      'Photo Image':    '', 'Photo Alt':       '', 'Photo Description': '', 'Photo URL': '',
      'Generated Images': ''
    };
  }

  const r = byBlog[rowNum];
  if (d.imageType === 'hero') {
    r['Hero Image'] = d.filename || ''; r['Hero Alt'] = d.altText || '';
    r['Hero Description'] = d.description || ''; r['Hero URL'] = d.driveUrl || '';
  } else if (d.imageType === 'info') {
    r['Info Image'] = d.filename || ''; r['Info Alt'] = d.altText || '';
    r['Info Description'] = d.description || ''; r['Info URL'] = d.driveUrl || '';
  } else if (d.imageType === 'photo') {
    r['Photo Image'] = d.filename || ''; r['Photo Alt'] = d.altText || '';
    r['Photo Description'] = d.description || ''; r['Photo URL'] = d.driveUrl || '';
  }
});

return Object.values(byBlog).map(r => {
  const count = [r['Hero Image'], r['Info Image'], r['Photo Image']].filter(Boolean).length;
  r.Status           = count === 3 ? 'completed' : count > 0 ? 'partial' : 'error';
  r['Generated Images'] = [r['Hero URL'], r['Info URL'], r['Photo URL']].filter(Boolean).join(', ');
  console.log('Row', r.row_number, ':', r.Status, '(' + count + ' images)');
  return { json: r };
});
